import React, { useState } from "react";
import "../styles/Professionals.css";

const professionals = [
    { id: 1, img: "/images/1.jpg", name: "John Doe" },
    { id: 2, img: "/images/2.jpg", name: "Jane Smith" },
    { id: 3, img: "/images/3.jpg", name: "Mike Johnson" },
    { id: 4, img: "/images/4.jpg", name: "Sarah Brown" },
    { id: 5, img: "/images/5.jpg", name: "David White" },
    { id: 6, img: "/images/1.jpg", name: "Emily Clark" },
    { id: 7, img: "/images/2.jpg", name: "James Wilson" },
    { id: 8, img: "/images/3.jpg", name: "Sophia Martinez" },
];

const Professionals = () => {
    const [modalOpen, setModalOpen] = useState(false);
    const [selectedProfessional, setSelectedProfessional] = useState(null);

    const openModal = (professional) => {
        setSelectedProfessional(professional);
        setModalOpen(true);
    };

    const closeModal = () => {
        setModalOpen(false);
        setSelectedProfessional(null);
    };

    return (
        <div className="professionals-section">
            <h2 className="section-title">OUR PROFESSIONALS</h2>
            <div className="professionals-grid">
                {professionals.map((pro) => (
                    <div key={pro.id} className="professional-card" onClick={() => openModal(pro)}>
                        <img src={pro.img} alt={pro.name} />
                        <div className="professional-name">{pro.name}</div>
                    </div>
                ))}
            </div>

            {modalOpen && selectedProfessional && (
                <div className="modal-overlay" onClick={closeModal}>
                    <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                        <div className="modal-left">
                            <img src={selectedProfessional.img} alt={selectedProfessional.name} />
                        </div>
                        <div className="modal-right">
                            <h3>{selectedProfessional.name}</h3>
                            <div className="professional-icon">
                                <img src="/path-to-icon/icon.png" alt="Icon" />
                            </div>
                            <div className="professional-email">
                                {selectedProfessional.name.toLowerCase().replace(" ", "")}@aco-law.com
                            </div>
                            <div className="professional-role">Associate</div>
                            <div className="professional-background">
                                <h4>Professional Background</h4>
                                <p>
                                    Christophorus Wisnoe Rurupadang (“Christo”) joined A&CO in February 2020. At A&CO,
                                    he focuses his practice on Litigation, Commercial Disputes, Intellectual Property, 
                                    Restructuring & Insolvency, Manpower, and General Corporate. He has worked on a 
                                    variety of suspension debts payment cases (“PKPU”) across a wide range of industries 
                                    and sectors.
                                </p>
                                <p>
                                    A 2019 graduate of Padjadjaran University Law Faculty, where he majored in Economic 
                                    Law, he was an active member of the university’s moot court community, and represented 
                                    his university in a national moot court competition. He was on the winning team in a moot 
                                    court competition held by Gadjah Mada University in 2016.
                                </p>
                                <p>
                                    Christo has passed the Indonesian Bar Exam organized by the Indonesian Advocates 
                                    Association (Perhimpunan Advokat Indonesia – PERADI) in 2020 and he is a licensed advocate 
                                    from the Indonesian Bar Association (PERADI) in 2022.
                                </p>
                            </div>
                            <div className="professional-experience">
                                <h4>Experience</h4>
                                <p>
                                    Christo’s main areas of practice include Debt Restructuring, Bankruptcy, Intellectual 
                                    Property, Civil and Commercial Litigation, and Family Law.
                                </p>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Professionals;
